      { front: { en: "Tequila Flight — Ballers", es: "Flight de Tequila — Ballers" }, back: { en: "Don Julio Añejo, 70th Anniversary, 1942. For guests who already know tequila and want the top of the line.", es: "Don Julio Añejo, 70 Aniversario, 1942. Para quien ya conoce el tequila y quiere lo mejor de la línea." } },
      { front: { en: "Chela's Signature Sangria", es: "Sangría Insignia de Chela's" }, back: { en: "Available white, red, or rosé — a good recommendation for a table that wants to share.", es: "Disponible blanca, roja, o rosada — una buena recomendación para una mesa que quiere compartir." } }
