      { q: { en: "Who must confirm the dish can be made safely before the order is rung in?", es: "¿Quién debe confirmar que el plato se puede hacer de forma segura antes de ingresar el pedido?" }, options: [{ en: "The chef/expo", es: "El chef/expo" }, { en: "No one, just send it", es: "Nadie, solo enviarlo" }, { en: "The guest", es: "El huésped" }, { en: "Another guest", es: "Otro huésped" }], correct: 0 },
      { q: { en: "What is the correct POS format for an allergy order?", es: "¿Cuál es el formato correcto en el POS para un pedido con alergia?" }, options: [{ en: "ALLERGY – [Allergen] – Table #", es: "ALLERGY – [Alérgeno] – Mesa #" }, { en: "No format needed", es: "No se necesita formato" }, { en: "Verbal only", es: "Solo verbal" }, { en: "Table number only", es: "Solo el número de mesa" }], correct: 0 },
      { q: { en: "Should shared dishes without the allergen still be labeled ALLERGY?", es: "¿Deben etiquetarse ALLERGY los platos compartidos que no contienen el alérgeno?" }, options: [{ en: "Yes, to prevent cross-contamination", es: "Sí, para prevenir contaminación cruzada" }, { en: "No, only the guest's own items", es: "No, solo los artículos del propio huésped" }, { en: "Only desserts", es: "Solo postres" }, { en: "Never", es: "Nunca" }], correct: 0 },
      { q: { en: "How should an allergy plate be delivered?", es: "¿Cómo debe entregarse un plato con alergia?" }, options: [{ en: "Placed directly in front of the guest with the allergy, table double-checked", es: "Colocado directamente frente al huésped con la alergia, verificando la mesa" }, { en: "Anywhere on the table", es: "En cualquier lugar de la mesa" }, { en: "Handed to any guest", es: "Entregado a cualquier huésped" }, { en: "Left at the bar for pickup", es: "Dejado en la barra para que lo recojan" }], correct: 0 }
