      { q: { en: "How does a busser directly help a server give better service?", es: "¿Cómo ayuda un busser directamente a que un server dé mejor servicio?" }, options: [{ en: "By handling clearing/resetting so the server can focus on the guest", es: "Manejando la limpieza/montaje para que el server se enfoque en el huésped" }, { en: "By taking over the server's sales", es: "Tomando las ventas del server" }, { en: "They don't interact at all", es: "No interactúan en absoluto" }, { en: "By staying in the kitchen only", es: "Quedándose solo en la cocina" }], correct: 0 }
