      { q: { en: "Why does knowing which section a table belongs to matter?", es: "¿Por qué importa saber a qué sección pertenece una mesa?" }, options: [{ en: "It tells you which server to communicate with about that table", es: "Te dice con qué server comunicarte sobre esa mesa" }, { en: "It doesn't matter at all", es: "No importa en absoluto" }, { en: "Only managers need to know sections", es: "Solo los gerentes necesitan saber las secciones" }, { en: "Sections change every night", es: "Las secciones cambian cada noche" }], correct: 0 }
